                         size_t pos, size_t length,
                         ZopfliLongestMatchCache *lmc)
{
    size_t i;
    size_t j = 0;
    unsigned bestlength = 0;
    unsigned char *cache;

    cache = &lmc->sublen[ZOPFLI_CACHE_LENGTH * pos * 3];
    if (length < 3)
